#include<bits/stdc++.h>
using namespace std;
typedef unsigned long long ull;
ull h[200010],h1[200010],base[200010],p=19991;
ull gethash(ull h[],int l,int r)
{
    return h[r]-h[l-1]*base[r-l+1];
}
bool check(int l,int ed)
{
    int st=1,r=l+ed-1;
    for(int i=1;i<4;i++)
    {
        int lt=-1,rt=ed-st+2;
        while(lt+1<rt)
        {
            int mid=(lt+rt)>>1;
            if(gethash(h,l,l+mid-1)==gethash(h1,st,st+mid-1))
            {
                lt=mid;
            }
            else
            {
                rt=mid;
            }
        }
        l+=lt+1;
        st+=lt+1;
        if(st>ed)
        {
            return true;
        }
    }
    return gethash(h,l,r)==gethash(h1,st,ed);
}
int solve()
{
    string str,s;
    cin>>str>>s;
    if(str.size()<s.size())
    {
        return 0;
    }
    int len1=str.size(),len2=s.size();
    str=" "+str;
    s=" "+s;
    for(int i=1;i<=len1;i++)
    {
        h[i]=h[i-1]*p+str[i];
    }
    for(int i=1;i<=len2;i++)
    {
        h1[i]=h1[i-1]*p+s[i];
    }
    int ans=0;
    for(int i=1;i+len2-1<=len1;i++)
    {
        if(check(i,len2))
        {
            ans++;
        }
    }
    return ans;
}
int main()
{
    base[0]=1;
    for(int i=1;i<=200000;i++)
    {
        base[i]=base[i-1]*p;
    }
    int t;
    scanf("%d",&t);
    while(t--)
    {
        printf("%d\n",solve());
    }
    return 0;
}
